mapper.select:
select * from catalogo
where cata_eliminado=false and (cata_nombre ilike #{c} or cata_descripcion ilike #{c})
order by cata_nombre;

select * from catalogo
where cata_eliminado = false
order by cata_nombre;

select t1.* from catalogo t1
inner join usuario_catalogo t2 on  t1.cata_id = t2.cata_id
where t2.pers_id = #{usuaId}

mapper.update:
UPDATE catalogo
SET  cata_nombre=#{cataNombre}, cata_estado=#{cataEstado}, cata_descripcion=#{cataDescripcion}, 
cata_carpeta=#{cataCarpeta}
WHERE cata_id = #{cataId}

mapper.delete:
UPDATE catalogo
set cata_eliminado = true, cata_ruta = ''
where cata_id = #{cataId}

mapper.insert:
INSERT INTO usuario_catalogo(
pers_id, cata_id)
VALUES (#{persId}, #{cataId});
